14	export const postJsonToApi = async <T>({
15	  url,
16	  headers,
17	  body,
18	  failedResponseHandler,
19	  successfulResponseHandler,
20	  abortSignal,
21	  fetch,
22	}: {
23	  url: string;
24	  headers?: Record<string, string | undefined>;
25	  body: unknown;
26	  failedResponseHandler: ResponseHandler<APICallError>;
27	  successfulResponseHandler: ResponseHandler<T>;
28	  abortSignal?: AbortSignal;
29	  fetch?: FetchFunction;
30	}) =>
31	  postToApi({
32	    url,
33	    headers: {
34	      'Content-Type': 'application/json',
35	      ...headers,
36	    },
37	    body: {
38	      content: JSON.stringify(body),
39	      values: body,
40	    },
41	    failedResponseHandler,
42	    successfulResponseHandler,
43	    abortSignal,
44	    fetch,
45	  });
