import { createPixelArt, PixelArtImageModelOptions } from '@ai-sdk/pixel-art';
import { generateImage } from 'ai';
import { presentImages } from '../../lib/present-image';
import { run } from '../../lib/run';

run(async () => {
  const pixelArt = createPixelArt();
  const { images } = await generateImage({
    model: pixelArt.image('pixel-art-v2'),
    prompt: 'A retro video game hero standing in a pixelated forest',
    size: '512x512',
