import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { InferSchema, Resolvable } from '@ai-sdk/provider-utils';
import {
  FetchFunction,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  resolve,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixel-art-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
    files,
    mask,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: SharedV3Warning[] = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'PixelArt does not support aspectRatio. Use size instead (e.g. "512x512").',
      });
    }

    if (files != null && files.length > 0) {
      warnings.push({
        type: 'unsupported',
        feature: 'files',
        details: 'PixelArt does not support input files.',
      });
    }

    if (mask != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'mask',
        details: 'PixelArt does not support image masking.',
      });
    }

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelArt',
      providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();
    const combinedHeaders = combineHeaders(
      await resolve(this.config.headers),
      headers,
    );

    const body: Record<string, unknown> = {
      prompt,
      model: this.modelId,
      n: n ?? 1,
      ...(size != null && { size }),
      ...(seed != null && { seed }),
      ...(pixelArtOptions?.style != null && { style: pixelArtOptions.style }),
      ...(pixelArtOptions?.pixelDensity != null && {
        pixel_density: pixelArtOptions.pixelDensity,
      }),
      ...(pixelArtOptions?.palette != null && {
        palette: pixelArtOptions.palette,
      }),
      ...(pixelArtOptions?.transparentBackground != null && {
        transparent_background: pixelArtOptions.transparentBackground,
      }),
    };

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images`,
      headers: combinedHeaders,
      body,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    const images = value.images.map(img => base64ToUint8Array(img.b64_json));

    return {
      images,
      warnings,
      providerMetadata: {
        pixelArt: {},
      },
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
    };
  }
}

function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export const pixelArtImageModelOptionsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      /**
       * Visual style of the generated image.
       * - 'pixel': classic pixel art look
       * - 'retro': retro game aesthetic
       * - '8bit': strict 8-bit color palette
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * Pixel density (pixels per unit). Higher values produce finer pixel grids.
       * Valid range: 1–64.
       */
      pixelDensity: z.number().int().min(1).max(64).optional(),

      /**
       * Restrict the color palette to a specific set of hex color strings.
       * Example: ['#ff0000', '#00ff00', '#0000ff']
       */
      palette: z.array(z.string()).optional(),

      /**
       * When true, the image background is rendered transparent (PNG only).
       */
      transparentBackground: z.boolean().optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

const pixelArtResponseSchema = z.object({
  images: z.array(
    z.object({
      b64_json: z.string(),
    }),
  ),
});

const pixelArtErrorSchema = z.object({
  error: z
    .object({
      message: z.string().optional(),
      code: z.string().optional(),
    })
    .optional(),
  message: z.string().optional(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => {
    const parsed = pixelArtErrorSchema.safeParse(error);
    if (!parsed.success) return 'Unknown PixelArt error';
    const { error: inner, message } = parsed.data;
    return inner?.message ?? message ?? 'Unknown PixelArt error';
  },
});

