import { FetchFunction } from '@ai-sdk/provider-utils';
import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { PixelArtImageModel } from './pixel-art-image-model';

const prompt = 'A pixel art castle at sunset';

const TEST_BASE64 = Buffer.from('test-image-data').toString('base64');

function createBasicModel({
  headers,
  fetch,
  currentDate,
}: {
  headers?: () => Record<string, string | undefined>;
  fetch?: FetchFunction;
  currentDate?: () => Date;
} = {}) {
  return new PixelArtImageModel('pixel-art-v1', {
    provider: 'pixel-art.image',
    baseURL: 'https://api.example.com/v1',
    headers: headers ?? (() => ({ Authorization: 'Bearer test-key' })),
    fetch,
    _internal: {
      currentDate,
    },
  });
}

describe('PixelArtImageModel', () => {
  const server = createTestServer({
    'https://api.example.com/v1/images': {
      response: {
        type: 'json-value',
        body: {
          images: [{ b64_json: TEST_BASE64 }],
        },
      },
    },
  });

  describe('doGenerate', () => {
    it('passes the correct body parameters including size and provider options', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: '512x512',
        aspectRatio: undefined,
        seed: 42,
        files: undefined,
        mask: undefined,
        providerOptions: {
          pixelArt: {
            style: '8bit',
            pixelDensity: 16,
          },
        },
      });

      expect(await server.calls[0].requestBodyJson).toStrictEqual({
        prompt,
        model: 'pixel-art-v1',
        n: 1,
        size: '512x512',
        seed: 42,
        style: '8bit',
        pixel_density: 16,
      });
    });

    it('omits optional fields when not provided', async () => {
      const model = createBasicModel();

      await model.doGenerate({
        prompt,
        n: 1,
        size: undefined,
        aspectRatio: undefined,
        seed: undefined,
        files: undefined,
        mask: undefined,
        providerOptions: {},
      });

      const body = await server.calls[0].requestBodyJson;
