import { createTestServer } from '@ai-sdk/test-server/with-vitest';
import { describe, expect, it } from 'vitest';
import { createPixelArt } from './pixel-art-provider';

const TEST_BASE64 = Buffer.from('test-image').toString('base64');

const server = createTestServer({
  'https://api.example.com/v1/images': {
    response: {
      type: 'json-value',
      body: {
        images: [{ b64_json: TEST_BASE64 }],
      },
    },
  },
});

describe('PixelArt provider', () => {
  it('creates image models via .image and .imageModel', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });

    const imageModel = provider.image('pixel-art-v1');
    const imageModel2 = provider.imageModel('retro-diffusion');

    expect(imageModel.provider).toBe('pixel-art.image');
    expect(imageModel.modelId).toBe('pixel-art-v1');
    expect(imageModel2.modelId).toBe('retro-diffusion');
    expect(imageModel.specificationVersion).toBe('v3');
  });

  it('configures baseURL, headers, and API key correctly', async () => {
    const provider = createPixelArt({
      apiKey: 'test-api-key',
      baseURL: 'https://api.example.com/v1',
      headers: {
        'X-Extra-Header': 'extra-value',
      },
    });

    const model = provider.image('pixel-art-v1');

    await model.doGenerate({
      prompt: 'A pixel art dragon',
      n: 1,
      size: '512x512',
      aspectRatio: undefined,
      seed: undefined,
      files: undefined,
      mask: undefined,
      providerOptions: {},
    });

    expect(server.calls[0].requestUrl).toBe(
      'https://api.example.com/v1/images',
    );
    expect(server.calls[0].requestMethod).toBe('POST');
    expect(server.calls[0].requestHeaders['authorization']).toBe(
      'Bearer test-api-key',
    );
    expect(server.calls[0].requestHeaders['x-extra-header']).toBe(
      'extra-value',
    );
    expect(await server.calls[0].requestBodyJson).toMatchObject({
      prompt: 'A pixel art dragon',
      model: 'pixel-art-v1',
      size: '512x512',
    });
    expect(server.calls[0].requestUserAgent).toContain('ai-sdk/pixel-art/');
  });

  it('throws NoSuchModelError for unsupported model types', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });

    expect(() => provider.languageModel('some-id')).toThrowError(
      'No such languageModel',
    );
    expect(() => provider.embeddingModel('some-id')).toThrowError(
      'No such embeddingModel',
    );
  });
});

